const c = (context.get('c') || 0) + 1;
context.set('c', c);
// load factor drives all three signals (correlated)
const load = 0.5 + 0.4 * Math.sin(2 * Math.PI * c / 100);
let temp = 60 + 20 * load + (Math.random() - 0.5) * 1.5;
let vib = 1.5 + 2.0 * load + (Math.random() - 0.5) * 0.2;
let current = 10 + 8 * load + (Math.random() - 0.5) * 0.5;
// every ~120 samples break the correlation: vibration rises without load
if (c % 120 === 0) vib += 3.0;
msg.payload = {
    temperature: +temp.toFixed(2),
    vibration: +vib.toFixed(3),
    current: +current.toFixed(2)
};
msg.topic = 'compressor-1/multivariate';
return msg;
